import React, { useState, useEffect } from 'react';
import { useNavigate, Routes, Route } from 'react-router-dom';
import {
    userService,
    patientService,
    doctorService,
    appointmentService,
    billingService,
} from '../services/api';
import '../styles/auth.css';

const AdminDashboard = () => {
    const navigate = useNavigate();
    const [activeMenu, setActiveMenu] = useState('overview');
    const [patients, setPatients] = useState([]);
    const [doctors, setDoctors] = useState([]);
    const [appointments, setAppointments] = useState([]);
    const [billings, setBillings] = useState([]);
    const [loading, setLoading] = useState(false);
    const [userMenuOpen, setUserMenuOpen] = useState(false);

    useEffect(() => {
        loadDashboardData();
    }, []);

    const loadDashboardData = async () => {
        setLoading(true);
        try {
            const [patientsRes, doctorsRes, appointmentsRes, billingsRes] = await Promise.all([
                patientService.getPatients(),
                doctorService.getDoctors(),
                appointmentService.getAppointments(),
                billingService.getBillings(),
            ]);
            setPatients(patientsRes.data.results || patientsRes.data);
            setDoctors(doctorsRes.data.results || doctorsRes.data);
            setAppointments(appointmentsRes.data.results || appointmentsRes.data);
            setBillings(billingsRes.data.results || billingsRes.data);
        } catch (error) {
            alert('Failed to load data');
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = () => {
        localStorage.removeItem('access_token');
        localStorage.removeItem('refresh_token');
        localStorage.removeItem('user');
        navigate('/login');
    };

    const deletePatient = async (id) => {
        if (window.confirm('Are you sure you want to delete this patient?')) {
            try {
                await patientService.updatePatient(id, { user: { is_active: false } });
                loadDashboardData();
            } catch (error) {
                alert('Failed to delete patient');
            }
        }
    };

    const deleteDoctor = async (id) => {
        if (window.confirm('Are you sure you want to delete this doctor?')) {
            try {
                await doctorService.updateDoctor(id, { is_available: false });
                loadDashboardData();
            } catch (error) {
                alert('Failed to delete doctor');
            }
        }
    };

    const stats = [
        { label: 'Total Patients', value: patients.length, icon: '👥' },
        { label: 'Total Doctors', value: doctors.length, icon: '👨‍⚕️' },
        { label: 'Appointments', value: appointments.length, icon: '📅' },
        { label: 'Billings', value: billings.length, icon: '💰' },
    ];

    return (
        <div className="dashboard-layout">
            <div className="sidebar">
                <div className="sidebar-header">🏥 Admin Panel</div>
                <ul className="sidebar-menu">
                    <li>
                        <a
                            href="#"
                            onClick={() => setActiveMenu('overview')}
                            className={activeMenu === 'overview' ? 'active' : ''}
                        >
                            📊 Overview
                        </a>
                    </li>
                    <li>
                        <a
                            href="#"
                            onClick={() => setActiveMenu('patients')}
                            className={activeMenu === 'patients' ? 'active' : ''}
                        >
                            👥 Patients
                        </a>
                    </li>
                    <li>
                        <a
                            href="#"
                            onClick={() => setActiveMenu('doctors')}
                            className={activeMenu === 'doctors' ? 'active' : ''}
                        >
                            👨‍⚕️ Doctors
                        </a>
                    </li>
                    <li>
                        <a
                            href="#"
                            onClick={() => setActiveMenu('appointments')}
                            className={activeMenu === 'appointments' ? 'active' : ''}
                        >
                            📅 Appointments
                        </a>
                    </li>
                    <li>
                        <a
                            href="#"
                            onClick={() => setActiveMenu('billings')}
                            className={activeMenu === 'billings' ? 'active' : ''}
                        >
                            💰 Billings
                        </a>
                    </li>
                </ul>
            </div>

            <div className="main-content">
                <div className="header">
                    <h1>Admin Dashboard</h1>
                    <div className="header-actions">
                        <div className="user-menu" onMouseLeave={() => setUserMenuOpen(false)}>
                            <button
                                className="user-btn"
                                onMouseEnter={() => setUserMenuOpen(true)}
                            >
                                👤 Account
                            </button>
                            {userMenuOpen && (
                                <div className="user-menu-dropdown">
                                    <button className="user-menu-item" onClick={() => setActiveMenu('profile')}>
                                        Profile
                                    </button>
                                    <button className="user-menu-item" onClick={handleLogout}>
                                        Logout
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {activeMenu === 'overview' && (
                    <div>
                        <div className="grid grid-4">
                            {stats.map((stat, idx) => (
                                <div key={idx} className="stats-card">
                                    <div className="stats-info">
                                        <h3>{stat.label}</h3>
                                        <div className="stats-value">{stat.value}</div>
                                    </div>
                                    <div className="stats-icon">{stat.icon}</div>
                                </div>
                            ))}
                        </div>

                        <div style={{ marginTop: '30px' }}>
                            <div className="card">
                                <div className="card-header">
                                    <h2>Recent Appointments</h2>
                                </div>
                                <div className="table-container">
                                    <table>
                                        <thead>
                                            <tr>
                                                <th>Patient</th>
                                                <th>Doctor</th>
                                                <th>Date</th>
                                                <th>Status</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {appointments.slice(0, 5).map((apt) => (
                                                <tr key={apt.id}>
                                                    <td>{apt.patient_name}</td>
                                                    <td>{apt.doctor_name}</td>
                                                    <td>{apt.appointment_date}</td>
                                                    <td>
                                                        <span className={`badge badge-${apt.status}`}>
                                                            {apt.status}
                                                        </span>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {activeMenu === 'patients' && (
                    <div className="card">
                        <div className="card-header">
                            <h2>Patients Management</h2>
                        </div>
                        <div className="table-container">
                            <table>
                                <thead>
                                    <tr>
                                        <th>Name</th>
                                        <th>Email</th>
                                        <th>Phone</th>
                                        <th>Blood Group</th>
                                        <th>Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {patients.map((patient) => (
                                        <tr key={patient.id}>
                                            <td>{patient.user?.first_name} {patient.user?.last_name}</td>
                                            <td>{patient.user?.email}</td>
                                            <td>{patient.user?.phone}</td>
                                            <td>{patient.blood_group}</td>
                                            <td>
                                                <button className="btn btn-sm btn-danger" onClick={() => deletePatient(patient.id)}>
                                                    Delete
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {activeMenu === 'doctors' && (
                    <div className="card">
                        <div className="card-header">
                            <h2>Doctors Management</h2>
                        </div>
                        <div className="table-container">
                            <table>
                                <thead>
                                    <tr>
                                        <th>Name</th>
                                        <th>Specialization</th>
                                        <th>Email</th>
                                        <th>Fee</th>
                                        <th>Available</th>
                                        <th>Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {doctors.map((doctor) => (
                                        <tr key={doctor.id}>
                                            <td>Dr. {doctor.user?.first_name} {doctor.user?.last_name}</td>
                                            <td>{doctor.specialization}</td>
                                            <td>{doctor.user?.email}</td>
                                            <td>${doctor.consultation_fee}</td>
                                            <td>{doctor.is_available ? '✓' : '✗'}</td>
                                            <td>
                                                <button className="btn btn-sm btn-danger" onClick={() => deleteDoctor(doctor.id)}>
                                                    Delete
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {activeMenu === 'appointments' && (
                    <div className="card">
                        <div className="card-header">
                            <h2>Appointments Management</h2>
                        </div>
                        <div className="table-container">
                            <table>
                                <thead>
                                    <tr>
                                        <th>Patient</th>
                                        <th>Doctor</th>
                                        <th>Date & Time</th>
                                        <th>Status</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {appointments.map((apt) => (
                                        <tr key={apt.id}>
                                            <td>{apt.patient_name}</td>
                                            <td>{apt.doctor_name}</td>
                                            <td>{apt.appointment_date} {apt.appointment_time}</td>
                                            <td>
                                                <span className={`badge badge-${apt.status}`}>
                                                    {apt.status}
                                                </span>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {activeMenu === 'billings' && (
                    <div className="card">
                        <div className="card-header">
                            <h2>Billings Management</h2>
                        </div>
                        <div className="table-container">
                            <table>
                                <thead>
                                    <tr>
                                        <th>Patient</th>
                                        <th>Total Amount</th>
                                        <th>Paid Amount</th>
                                        <th>Balance</th>
                                        <th>Status</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {billings.map((bill) => (
                                        <tr key={bill.id}>
                                            <td>{bill.appointment_details?.patient_name}</td>
                                            <td>${bill.total_amount}</td>
                                            <td>${bill.paid_amount}</td>
                                            <td>${bill.balance}</td>
                                            <td>
                                                <span className={`badge badge-${bill.payment_status}`}>
                                                    {bill.payment_status}
                                                </span>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default AdminDashboard;
